module portfolio_optimizer (
    input [4:0] weight1,
    input [4:0] weight2,
    output reg [4:0] optimized_weight1,
    output reg [4:0] optimized_weight2
);
    wire [5:0] sum_of_weights;
    assign sum_of_weights = weight1 + weight2;

    always @(*) begin
        if (sum_of_weights > 16) begin
            optimized_weight1 = (weight1 * 16) / sum_of_weights;
            optimized_weight2 = (weight2 * 16) / sum_of_weights;
        end else begin
            optimized_weight1 = weight1;
            optimized_weight2 = weight2;
        end
    end
endmodule
